const items = [];
const parentItem = $input.item;
const midias = parentItem.json.Midia || [];
const caption = parentItem.json.caption || '';
const node = parentItem.json.node_insta || '';

for (let i = 0; i < midias.length; i++) {
  items.push({
    json: {
      media_url: midias[i],
      caption: caption,
      node: node,
      index: i,
      total: midias.length
    }
  });
}
return items;

const items = $input.all();
return items.map((item, idx) => {
  // Check binary mimeType first (HEAD requests store content-type there)
  const binaryMime = item.binary && item.binary.data ? item.binary.data.mimeType : '';
  const headersMime = (item.json.headers || {})["content-type"] || (item.json.headers || {})["Content-Type"] || '';
  const contentType = binaryMime || headersMime;
  const isVideo = contentType.toLowerCase().startsWith('video/');

  // Restore original item details
  const original = $('Split Carousel Images').all()[idx].json;

  return {
    json: {
      ...original,
      media_type: isVideo ? 'VIDEO' : 'IMAGE'
    }
  };
});

const ids = $input.all().map(item => item.json.id);
return {
  json: {
    children_ids: ids.join(',')
  }
};

