const items = $input.all();
const videos = items.filter(item => item.json.media_type === 'VIDEO');
const images = items.filter(item => item.json.media_type === 'IMAGE');

if (videos.length > 0) {
  return [{
    json: {
      has_video: true,
      video_url: videos[0].json.media_url,
      caption: videos[0].json.caption,
      node_facebook: videos[0].json.node_facebook
    }
  }];
} else {
  return images.map(item => ({
    json: {
      has_video: false,
      image_url: item.json.media_url,
      caption: item.json.caption,
      node_facebook: item.json.node_facebook
    }
  }));
}

const ids = $input.all().map(item => ({ media_fbid: item.json.id }));
return {
  json: {
    attached_media: JSON.stringify(ids)
  }
};

for (const item of $input.all()) {
  delete item.json.node_insta; 
}
return $input.all();

for (const item of $input.all()) {
  delete item.json.node_facebook; 
}
return $input.all();
